import{_ as a,o as e,c as r,a0 as o}from"./chunks/framework.4diiUCsN.js";const c=JSON.parse('{"title":"马后炮","description":"","frontmatter":{},"headers":[],"relativePath":"pages/mahoupao/index.md","filePath":"pages/mahoupao/index.md"}'),s={name:"pages/mahoupao/index.md"};function h(n,t,i,l,p,d){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="马后炮" tabindex="-1">马后炮 <a class="header-anchor" href="#马后炮" aria-label="Permalink to &quot;马后炮&quot;">​</a></h1><p>qlib 模型对 CSI300 的预测准确度究竟如何？欢迎点击左侧 <a href="https://touhoufan2024.github.io/qlibAssistant/pages/mahoupao/review_result.html" target="_blank" rel="noreferrer">复盘统计分析</a> 查看详细分析结果。 也可以查看 <a href="/qlibAssistant/pages/mahoupao/nav_curve.html">净值曲线（Lightweight Charts）</a> 观察策略与 CSI300 的累计净值变化。</p><p>我们会定期对历史预测表现进行汇总和评估，持续跟踪模型的实际准确性。</p><p>如果需要更完整、详细的历史统计 CSV 文件（未直接展示于网页），可前往 <a href="https://github.com/touhoufan2024/qlibAssistant/tree/qlib_score/review_csv" target="_blank" rel="noreferrer">qlib_score 分支的 review_csv 文件夹</a> 获取原始数据，自行比对或核查。</p><p>表格字段说明：</p><table tabindex="0"><thead><tr><th>instrument</th><th>avg_score</th><th>real_label</th><th>n1close</th><th>n2high</th></tr></thead><tbody><tr><td>股票代码</td><td>预测持有一天收益</td><td>实际持有一天收益</td><td>次日收盘价（买入时机）</td><td>第三日最高价（用于止盈分析）</td></tr></tbody></table><h2 id="q-a" tabindex="-1">Q &amp; A <a class="header-anchor" href="#q-a" aria-label="Permalink to &quot;Q &amp; A&quot;">​</a></h2><p><strong>Q：为什么只统计了止盈，没有考虑止损？</strong><br> A：目前依赖的是 qlib 的日线数据，只能获得每日的最高价与最低价，无法得到日内的详尽分时 K线。因此只能统计止盈相关的表现，止损数据暂时无法精确回测。</p><p><strong>Q：为什么 n1close 和 n2high 的数值与真实价格不同？</strong><br> A：为避免版权纠纷并便于模型训练，qlib 所用原始数据做过缩放处理，虽然绝对价格和真实市场有差异，但各类收益和相对比值是准确的。</p><p>最后补充一点，实盘操作时无需机械按照收盘价买入。若当日出现明显上涨，收盘买入可能会偏高，不妨挂个较低的价格，冷静等待更合适的买入机会。</p>',10)])])}const b=a(s,[["render",h]]);export{c as __pageData,b as default};
